/**
 * @summary Log current weight
 */
export const logWeight = async (weightInput: WeightInput, options?: RequestInit): Promise<WeightEntry> => {

  return customFetch<WeightEntry>(getLogWeightUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      weightInput,)
  }
);}




export const getLogWeightMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof logWeight>>, TError,{data: BodyType<WeightInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof logWeight>>, TError,{data: BodyType<WeightInput>}, TContext> => {

const mutationKey = ['logWeight'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof logWeight>>, {data: BodyType<WeightInput>}> = (props) => {
          const {data} = props ?? {};

          return  logWeight(data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type LogWeightMutationResult = NonNullable<Awaited<ReturnType<typeof logWeight>>>
    export type LogWeightMutationBody = BodyType<WeightInput>
